import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.7R1OEGYz.js";const p=JSON.parse('{"title":"Verified codes and the issuer","description":"","frontmatter":{},"headers":[],"relativePath":"internals/codes.md","filePath":"internals/codes.md"}'),i={name:"internals/codes.md"};function n(r,e,d,c,h,l){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="verified-codes-and-the-issuer" tabindex="-1">Verified codes and the issuer <a class="header-anchor" href="#verified-codes-and-the-issuer" aria-label="Permalink to &quot;Verified codes and the issuer&quot;">​</a></h1><p>Suho uses one-time codes for two things: large transfers to strangers, and account recovery. A code is an attestation on EAS, issued by the Suho code attester.</p><h2 id="what-a-code-is" tabindex="-1">What a code is <a class="header-anchor" href="#what-a-code-is" aria-label="Permalink to &quot;What a code is&quot;">​</a></h2><p><code>SuhoCodeAttester</code> issues a code as a revocable EAS attestation. The stored value is a hash, not the code itself. The hash is <code>keccak256(subject, domain, code)</code>.</p><p>The domain binds the code to a purpose.</p><ul><li>Transfer: <code>suho.guard:&lt;account&gt;:&lt;recipient&gt;:&lt;amount&gt;</code></li><li>Recovery: <code>suho.arise:&lt;account&gt;:&lt;newKeyHash&gt;</code></li></ul><p>Because the code hash commits to the domain, a code observed in the mempool is useless for any other account or action. <code>verifyAndConsume</code> checks that the attestation exists, is unrevoked, is unexpired, and is unused, then marks it consumed. Re-issuing for the same subject and domain revokes the old code on chain.</p><h2 id="the-verification-service" tabindex="-1">The verification service <a class="header-anchor" href="#the-verification-service" aria-label="Permalink to &quot;The verification service&quot;">​</a></h2><p>Codes are delivered out of band. In the app, that channel is a page served by the guardian at <code>/issuer</code>, styled as the Verification Service. It lists active codes per account, each with a live countdown. Click a code to copy it.</p><p>The page carries one honest line. On mainnet, codes are delivered by the issuer&#39;s own app. This page simulates that channel for the testnet issuer.</p><p>The console and a local log stay as fallbacks. The design reason for keeping delivery out of band is the whole point: a drainer in the browser cannot produce a code it never received.</p><h2 id="expiry" tabindex="-1">Expiry <a class="header-anchor" href="#expiry" aria-label="Permalink to &quot;Expiry&quot;">​</a></h2><p>Codes last ten minutes. If a code expires while an input is open, the app disables submit and offers to request a new one. Entering an expired code maps to a plain sentence: &quot;Code expired. Request a fresh one.&quot;</p>',13)])])}const f=a(i,[["render",n]]);export{p as __pageData,f as default};
